 {"id":"franken_networkx-2tei","title":"Native Pajek parser boundary for cargo-fuzz coverage","description":"Pajek read/parse remains NetworkX-delegated in Python, so E6 can only fuzz native Rust parser boundaries today. Add a native Rust Pajek parser boundary (or another instrumentable Rust ingestion layer) so cargo-fuzz can cover Pajek inputs instead of leaving them outside the parser fuzz suite.","status":"closed","priority":3,"issue_type":"task","created_at":"2026-04-15T04:31:38.164584457Z","created_by":"ubuntu","updated_at":"2026-04-15T20:09:43.501616506Z","closed_at":"2026-04-15T20:09:43.498739325Z","close_reason":"Added native Rust Pajek parser (read_pajek, read_digraph_pajek) with cargo-fuzz target fuzz_pajek. Supports *Vertices, *Edges, *Arcs sections with optional weights. Added to CI smoke and nightly soak.","source_repo":".","compaction_level":0,"original_size":0}
 {"id":"franken_networkx-2tsg","title":"parity: edge_connectivity missing flow_func param","description":"edge_connectivity(G, s, t) is missing flow_func param. NX: (G, s=None, t=None, flow_func=None, cutoff=None). FNX: (g, s=None, t=None, cutoff=None). Add wrapper delegating to NX when flow_func specified.","status":"closed","priority":2,"issue_type":"task","created_at":"2026-04-21T12:38:50.231307514Z","created_by":"ubuntu","updated_at":"2026-04-21T12:40:16.755870893Z","closed_at":"2026-04-21T12:40:16.753770827Z","close_reason":"Added wrapper delegating to NX when flow_func provided","source_repo":".","compaction_level":0,"original_size":0}
